from dataclasses import dataclass, field
from datetime import date

@dataclass
class BlockerResolutionPlan:
    blocker_description: str
    root_cause: str            # what is causing the criterion to miss its threshold
    proposed_fix: str          # what change will resolve the root cause
    fix_owner: str
    target_completion_date: date
    success_criteria: str      # how the team will know the blocker is resolved

    # Filled in after resolution attempt
    actual_completion_date: date = None
    resolved: bool = False
    resolution_notes: str = ""

    def is_overdue(self, today: date) -> bool:
        return not self.resolved and today > self.target_completion_date

    def status_line(self) -> str:
        if self.resolved:
            return f"RESOLVED ({self.actual_completion_date}): {self.blocker_description}"
        return f"OPEN (target {self.target_completion_date}): {self.blocker_description}"

@dataclass
class ExtendedBetaPlan:
    feature_name: str
    extension_start_date: date
    follow_up_review_date: date
    blockers: list[BlockerResolutionPlan] = field(default_factory=list)
    max_extension_cycles: int = 2   # prevents indefinite extension

    def all_blockers_resolved(self) -> bool:
        return all(b.resolved for b in self.blockers)

    def ready_for_follow_up(self) -> bool:
        return self.all_blockers_resolved()

    def status_report(self, today: date) -> str:
        overdue = [b for b in self.blockers if b.is_overdue(today)]
        resolved = [b for b in self.blockers if b.resolved]
        open_items = [b for b in self.blockers if not b.resolved]
        lines = [
            f"Extended beta status: {self.feature_name}",
            f"Follow-up review: {self.follow_up_review_date}",
            f"Resolved: {len(resolved)}/{len(self.blockers)}",
        ]
        if overdue:
            lines.append(f"OVERDUE ({len(overdue)}): " + "; ".join(b.blocker_description for b in overdue))
        if open_items:
            lines.append("Open: " + "; ".join(b.status_line() for b in open_items))
        return "\n".join(lines)
